parameters.jsonBody:
={
  "embeds": [
    {
      "title": "🚨 AEGIS-SENTINEL: CHEATING ANOMALY DETECTED",
      "description": "An anomalous game state progression and timing pattern was intercepted in scores telemetry pipeline.",
      "color": 15158332,
      "fields": [
        {
          "name": "👤 Player Username",
          "value": "`{{ $json.username }}`",
          "inline": true
        },
        {
          "name": "🎮 Captured Score",
          "value": "**{{ $json.score }}**",
          "inline": true
        },
        {
          "name": "🛡️ Detection Trigger",
          "value": "`{{ $json.reason }}`"
        },
        {
          "name": "💻 Hardware Profile",
          "value": "```\n{{ $json.hardwareProfile }}\n```"
        },
        {
          "name": "📊 Telemetry Diagnostics",
          "value": "• **Accuracy:** {{ $json.telemetrySummary.accuracy }}%\n• **Hits/Misses:** {{ $json.telemetrySummary.hits }} Hits / {{ $json.telemetrySummary.misses }} Misses\n• **Run Duration:** {{ $json.telemetrySummary.durationSeconds }}s\n• **Target Velocity:** {{ $json.telemetrySummary.inputVelocity }} targets/sec"
        }
      ],
      "footer": {
        "text": "AimSync Anti-Cheat Edge Daemon"
      },
      "timestamp": "{{ new Date().toISOString() }}"
    }
  ]
}
